//The getCompetitiveSummary operation allows you to retrieve the current featured offers for a batch of items by ASIN. This operation allows up to 20 ASIN requests in a single batch. Call the getCompetitiveSummary operation, passing the following parameters:


{
  "requests": [
    {
      "asin": "{{ASIN}}",
      "marketplaceId": "{{marketplace}}",
      "includedData": [
        "featuredBuyingOptions",
        "referencePrices",
        "lowestPricedOffers"
      ],
      "method": "GET",
      "uri": "/products/pricing/2022-05-01/items/competitiveSummary"
    }
  ]
}

